    /* ── Task item creation helper ── */
    function createTaskItem(task, idx, tabType) {
      const li = document.createElement('li');
      li.className = 'task-item' + (task.done ? ' done' : '');

      // Check if task is overdue
      if (task.deadline && !task.done) {
        const isOverdue = checkOverdue(task.deadline, tabType);
        if (isOverdue) li.classList.add('overdue');
      }

      // Carbon checkbox
      const cbWrap = document.createElement('label');
      cbWrap.className = 'cds--checkbox-wrapper';
      cbWrap.title = task.done ? 'Mark incomplete' : 'Mark complete';

      const cb = document.createElement('input');
      cb.type = 'checkbox';
      cb.className = 'cds--checkbox';
      cb.checked = task.done;
      cb.setAttribute('aria-label', task.text);
      cb.addEventListener('change', () => toggleTask(idx));

      const cbAppearance = document.createElement('span');
      cbAppearance.className = 'cds--checkbox-appearance';

      cbWrap.appendChild(cb);
      cbWrap.appendChild(cbAppearance);

      const label = document.createElement('span');
      label.className = 'task-label';

      const taskText = document.createElement('span');
      taskText.textContent = task.text;
      label.appendChild(taskText);

      // Add deadline display
      if (task.deadline && tabType !== 'weekly') {
        const deadlineSpan = document.createElement('span');
        deadlineSpan.className = 'task-deadline';
        deadlineSpan.textContent = formatDeadline(task.deadline, tabType);
        label.appendChild(deadlineSpan);
      }

      label.addEventListener('click', () => toggleTask(idx));

      const del = document.createElement('button');
      del.className = 'cds--btn--ghost--icon';
      del.innerHTML = '&#x2715;';
      del.title = 'Delete task';
      del.setAttribute('aria-label', 'Delete: ' + task.text);
      del.addEventListener('click', () => deleteTask(idx));

      li.appendChild(cbWrap);
      li.appendChild(label);
      li.appendChild(del);

      return li;
    }

    /* ── Weekly column rendering ── */
    function renderWeeklyColumns(list, empty, tasks) {
      const { grouped, weekDays } = groupTasksByDay(tasks);

      // Create column container
      const columnsContainer = document.createElement('div');
      columnsContainer.className = 'weekly-columns';

      weekDays.forEach(day => {
        const column = document.createElement('div');
        column.className = 'day-column';

        // Column header
        const header = document.createElement('div');
        header.className = 'day-column-header';
        header.innerHTML = `${day.shortName}<span class="day-name">${day.date.split('-')[2]}</span>`;
        column.appendChild(header);

        // Column tasks
        const tasksContainer = document.createElement('div');
        tasksContainer.className = 'day-column-tasks';

        const dayTasks = grouped[day.name];
        if (dayTasks.length === 0) {
          const emptyMsg = document.createElement('div');
          emptyMsg.className = 'day-column-empty';
          emptyMsg.textContent = 'No tasks';
          tasksContainer.appendChild(emptyMsg);
        } else {
          dayTasks.forEach(task => {
            const taskItem = createTaskItem(task, task.index, 'weekly');
            // Wrap in a row for column layout
            const row = document.createElement('div');
            row.className = 'task-item-row';
            row.appendChild(taskItem);
            tasksContainer.appendChild(taskItem);
          });
        }

        column.appendChild(tasksContainer);
        columnsContainer.appendChild(column);
      });

      list.appendChild(columnsContainer);
      empty.style.display = 'none';
    }

